{
  "permissions": {
    "allow": [
      "Bash(mkdir:*)",
      "Bash(npx prettier --write:*)",
      "Read(.claude/**)",
      "Write(.claude/**)",
      "Edit(.claude/**)",
      "Read(tasks/**)",
      "Write(tasks/**)",
      "Edit(tasks/**)",
      "Bash(git add:*)",
      "Bash(yarn type-check:*)",
      "Bash(cat:*)",
      "Bash(npx tsc --noEmit)",
      "Bash(yarn lint:*)",
      "Bash(yarn test:*)"
    ],
    "deny": ["Read(.env)", "Read(../.env)"],
    "ask": []
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write",
        "hooks": [
          {
            "type": "command",
            "command": "git add --ignore-errors \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          }
        ]
      }
    ]
  }
}

